// Get avatar data
const data = $items("Merge for concept and Avatar Data", 0, 0)[0].json;

const avatarNames = data["Avatar Names"];
const urls = data["Reference URLs"];

// Get master shot URL safely
const masterShotUrl = $items("Upload file", 0, 0)[0].json.webContentLink;

// Build mapping
const mapping = {};
const image_urls = [];

// Add master shot at index 0
image_urls.push(masterShotUrl);

// Avatar images start from index 1
avatarNames.forEach((name, index) => {
  const imageIndex = index + 1;
  mapping[name] = `<image:${imageIndex}>`;
  image_urls.push(urls[index]);
});

// Get fields
const storyShot = $json.StoryShots.framePrompt || "";
const clothing = $json.ClothingDetails || "";

// Combine prompt
let combinedPrompt = `${storyShot}`;

// Replace placeholders
avatarNames.forEach((name, index) => {
  const imageIndex = index + 1;
  const placeholder1 = `<<${name}>>`;
  const placeholder2 = `<<${name.replace(/[0-9]/g,"")}>>`;

  combinedPrompt = combinedPrompt.replaceAll(placeholder1, `<image:${imageIndex}>`);
  combinedPrompt = combinedPrompt.replaceAll(placeholder2, `<image:${imageIndex}>`);
});

// Determine the shot number based on the item's position in the loop
// We add 1 so the first row starts at 1 instead of 0
const shot_num = $itemIndex + 1;

return {
  json: {
    ...$json,
    shot_num, // Added the new key here
    shot_prompt: storyShot,
    kling_prompt: combinedPrompt,
    image_urls,
    mapping
  }
};

return $items("fetch response").map(item => {
  return {
    json: {
      ...item.json,          // Keep original data
      ...item.json.images    // Extract and flatten everything inside "images"
    }
  };
});

